#!/usr/bin/env bash
# experiments/run-all.sh — EXP framework orchestrator
#
# Reads experiments/manifest.json (generated by gen-manifest.py if absent) and
# dispatches bats/smoke/research executions, writing result JSON to
# .audit/<run-id>/experiments/EXP-NNN.json plus aggregated index.json.
#
# Usage:
#   bash experiments/run-all.sh [--category <letter>|all] [--runner-type bats|smoke|research|all] [--dry-run]
#
# Defaults: --category all, --runner-type bats
#
# Exit codes:
#   0  all targeted EXPs passed (or dry-run completed)
#   1  one or more bats EXP failures
#   2  invocation error (missing tool, bad arg, etc.)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
MANIFEST="${SCRIPT_DIR}/manifest.json"

CATEGORY="all"
RUNNER_TYPE="bats"
DRY_RUN=0

usage() {
    sed -n '2,12p' "${BASH_SOURCE[0]}" | sed 's/^# //;s/^#//'
}

while [[ $# -gt 0 ]]; do
    case "$1" in
        --category)    CATEGORY="$2"; shift 2 ;;
        --runner-type) RUNNER_TYPE="$2"; shift 2 ;;
        --dry-run)     DRY_RUN=1; shift ;;
        --help|-h)     usage; exit 0 ;;
        *)             echo "error: unknown option: $1" >&2; usage; exit 2 ;;
    esac
done

if ! command -v jq >/dev/null 2>&1; then
    echo "error: jq is required" >&2
    exit 2
fi

# Always regenerate manifest to stay in sync with experiment-index.html
python3 "${SCRIPT_DIR}/gen-manifest.py" >/dev/null

# Anti-sabotage Pre-run audits (Phase F-3、registry-schema.html §10.3).
# Skipped only when explicitly opted-out via SKIP_PRERUN_AUDIT=1.
if [[ "${SKIP_PRERUN_AUDIT:-0}" != "1" ]]; then
    if ! python3 "${SCRIPT_DIR}/verify-source-check.py" \
            ${VERIFY_SOURCE_SKIP_NETWORK:+--skip-network} --quiet; then
        echo "error: verify-source-check failed; rerun with --quiet=false to see failed URLs" >&2
        echo "       (set SKIP_PRERUN_AUDIT=1 to bypass — anti-sabotage opt-out, must be intentional)" >&2
        exit 2
    fi
    if ! python3 "${SCRIPT_DIR}/audit-bats-quality.py" --quiet \
            "${REPO_ROOT}/test-fixtures/experiments"; then
        echo "error: audit-bats-quality failed; rerun without --quiet to see WARN/CRITICAL" >&2
        echo "       (set SKIP_PRERUN_AUDIT=1 to bypass — anti-sabotage opt-out, must be intentional)" >&2
        exit 2
    fi
    # Phase G: status transition + drift audit. WARN-only mode (lattice violation は
    # Phase F-4 multi-stage upgrade pattern により user judgment 済み、CRITICAL でも abort しない).
    # 厳格 abort モードは将来 SKIP_STATUS_LOG_BLOCKING=0 で enable 予定。
    # baseline SHA256 は .audit/ 配下 (git ignored runtime artifact)、不在なら自動生成。
    AUDIT_STATUS_BASELINE="${REPO_ROOT}/.audit/gen-manifest-baseline.sha256"
    if [[ ! -f "$AUDIT_STATUS_BASELINE" ]]; then
        mkdir -p "$(dirname "$AUDIT_STATUS_BASELINE")"
        sha256sum "${SCRIPT_DIR}/gen-manifest.py" | awk '{print $1}' > "$AUDIT_STATUS_BASELINE"
        echo "info: gen-manifest baseline initialized: $AUDIT_STATUS_BASELINE" >&2
    fi
    python3 "${SCRIPT_DIR}/audit-status-log.py" --quiet \
        --baseline-file "$AUDIT_STATUS_BASELINE" \
        --output "${REPO_ROOT}/.audit/audit-status-log-latest.json" || \
        echo "warning: audit-status-log violations detected (output: .audit/audit-status-log-latest.json)" >&2
fi

BATS_BIN="${REPO_ROOT}/plugins/twl/tests/lib/bats-core/bin/bats"
if [[ ! -x "$BATS_BIN" ]]; then
    BATS_BIN="$(command -v bats || true)"
fi
if [[ -z "$BATS_BIN" || ! -x "$BATS_BIN" ]]; then
    echo "error: bats not found (tried submodule and PATH)" >&2
    exit 2
fi

# Compose jq filter
JQ_FILTER='.experiments[]'
[[ "$CATEGORY" != "all" ]] && JQ_FILTER+=" | select(.category == \"${CATEGORY}\")"
case "$RUNNER_TYPE" in
    bats)     JQ_FILTER+=' | select(.runner_type == "bats" or .runner_type == "bats+smoke")' ;;
    smoke)    JQ_FILTER+=' | select(.runner_type == "smoke" or .runner_type == "bats+smoke")' ;;
    research) JQ_FILTER+=' | select(.runner_type == "research")' ;;
    all)      : ;;
    *)        echo "error: --runner-type must be bats|smoke|research|all" >&2; exit 2 ;;
esac

RUN_ID="$(date -u +%Y%m%d-%H%M%S)-experiments"
AUDIT_DIR="${REPO_ROOT}/.audit/${RUN_ID}/experiments"
mkdir -p "$AUDIT_DIR"

declare -i RUN_COUNT=0 PASS_COUNT=0 FAIL_COUNT=0 SKIP_COUNT=0

emit_result() {
    # emit_result <exp_id> <pass: true|false|null> <reason> <verify_source>
    local id="$1" pass="$2" reason="$3" vs="$4"
    local ts; ts="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
    jq -n --arg id "$id" --arg ts "$ts" --argjson pass "$pass" --arg reason "$reason" --arg vs "$vs" \
        '{exp_id: $id, ts: $ts, pass: $pass, reason: $reason, verify_source: $vs}' \
        > "${AUDIT_DIR}/${id}.json"
}

# ── smoke fixtures (1 board + 1 repo を 6 件 smoke で reuse) ────
# smoke runner_type の EXP が 1 件以上ある場合のみ事前 setup を実行
SMOKE_COUNT=$(jq -c "$JQ_FILTER" "$MANIFEST" | jq -s 'map(select(.runner_type == "smoke")) | length')
SMOKE_FIXTURES_OWNED=false

_smoke_fixtures_cleanup() {
    if [[ "$SMOKE_FIXTURES_OWNED" == "true" && -n "${TWL_SMOKE_BOARD_ID:-}" ]]; then
        echo "[smoke fixtures] teardown..." >&2
        bash "${REPO_ROOT}/experiments/teardown-test-board.sh" 2>&1 | tail -5 >&2 || true
        SMOKE_FIXTURES_OWNED=false
    fi
}

if [[ "$DRY_RUN" -eq 0 && "$SMOKE_COUNT" -gt 0 ]]; then
    echo "[smoke fixtures] setup ($SMOKE_COUNT smoke EXP 検出)..." >&2
    SMOKE_SETUP_LOG="${AUDIT_DIR}/smoke-setup.log"
    if SETUP_OUT=$(bash "${REPO_ROOT}/experiments/setup-test-board.sh" 2>>"$SMOKE_SETUP_LOG"); then
        eval "$SETUP_OUT"
        SMOKE_FIXTURES_OWNED=true
        # Fix 2: SIGTERM/SIGINT でも cleanup を発火 (Ctrl+C, daemon kill 対応)
        trap '_smoke_fixtures_cleanup' EXIT INT TERM
        echo "[smoke fixtures] BOARD_NUM=${TWL_SMOKE_BOARD_NUM} REPO=${TWL_SMOKE_REPO_FULL}" >&2
    else
        echo "[smoke fixtures] setup failed (log: ${SMOKE_SETUP_LOG}):" >&2
        tail -10 "$SMOKE_SETUP_LOG" >&2 || true
        echo "smoke EXP は SKIP されます" >&2
    fi
fi

while IFS= read -r exp_json; do
    EXP_ID=$(jq -r '.exp_id' <<<"$exp_json")
    CAT=$(jq -r '.category' <<<"$exp_json")
    RUNNER=$(jq -r '.runner_type // "null"' <<<"$exp_json")
    BATS_PATH=$(jq -r '.bats_path // empty' <<<"$exp_json")
    VS=$(jq -r '.verify_source // empty' <<<"$exp_json")

    if [[ "$DRY_RUN" -eq 1 ]]; then
        printf '[dry-run] %-8s category=%s runner=%-10s bats=%s\n' \
            "$EXP_ID" "$CAT" "$RUNNER" "${BATS_PATH:-N/A}"
        RUN_COUNT+=1
        continue
    fi

    case "$RUNNER" in
        bats|bats+smoke)
            if [[ -z "$BATS_PATH" ]]; then
                emit_result "$EXP_ID" 'null' "bats_path not set in manifest" "$VS"
                SKIP_COUNT+=1
                echo "SKIP ${EXP_ID} (bats_path missing)" >&2
                continue
            fi
            FULL="${REPO_ROOT}/${BATS_PATH}"
            if [[ ! -f "$FULL" ]]; then
                emit_result "$EXP_ID" 'null' "bats file not found: ${BATS_PATH}" "$VS"
                SKIP_COUNT+=1
                echo "SKIP ${EXP_ID} (file not found: ${BATS_PATH})" >&2
                continue
            fi
            RUN_COUNT+=1
            LOG="${AUDIT_DIR}/${EXP_ID}.log"
            if "$BATS_BIN" "$FULL" >"$LOG" 2>&1; then
                emit_result "$EXP_ID" 'true' "" "$VS"
                PASS_COUNT+=1
                echo "PASS ${EXP_ID}" >&2
            else
                emit_result "$EXP_ID" 'false' "bats failure; log: ${LOG}" "$VS"
                FAIL_COUNT+=1
                echo "FAIL ${EXP_ID} (log: ${LOG})" >&2
            fi
            ;;
        smoke)
            SMOKE_PATH=$(jq -r '.smoke_path // empty' <<<"$exp_json")
            if [[ -z "$SMOKE_PATH" ]]; then
                emit_result "$EXP_ID" 'null' "smoke_path not set in manifest" "$VS"
                SKIP_COUNT+=1
                echo "SKIP ${EXP_ID} (smoke_path missing)" >&2
                continue
            fi
            FULL_SMOKE="${REPO_ROOT}/${SMOKE_PATH}"
            if [[ ! -f "$FULL_SMOKE" ]]; then
                emit_result "$EXP_ID" 'null' "smoke file not found: ${SMOKE_PATH}" "$VS"
                SKIP_COUNT+=1
                echo "SKIP ${EXP_ID} (smoke file not found: ${SMOKE_PATH})" >&2
                continue
            fi
            RUN_COUNT+=1
            SMOKE_LOG="${AUDIT_DIR}/${EXP_ID}.log"
            # smoke.sh は pass=false でも exit 1、stdout JSON は残す。
            # exit code を握り潰しつつ stdout を保持 (|| SMOKE_RESULT="" は stdout 上書きで NG)
            set +e
            SMOKE_RESULT=$(bash "$FULL_SMOKE" \
                --log-dir "$AUDIT_DIR" \
                --run-id "$RUN_ID" \
                2>>"$SMOKE_LOG")
            SMOKE_EXIT=$?
            set -e
            SMOKE_PASS=$(jq -r '.pass' <<<"$SMOKE_RESULT" 2>/dev/null || echo "null")
            if [[ "$SMOKE_PASS" == "true" ]]; then
                # smoke.sh emit JSON を直接 .audit/<run-id>/EXP-NNN.json に保存
                echo "$SMOKE_RESULT" > "${AUDIT_DIR}/${EXP_ID}.json"
                PASS_COUNT+=1
                echo "PASS ${EXP_ID}" >&2
            elif [[ "$SMOKE_PASS" == "false" ]]; then
                echo "$SMOKE_RESULT" > "${AUDIT_DIR}/${EXP_ID}.json"
                FAIL_COUNT+=1
                echo "FAIL ${EXP_ID} (log: ${SMOKE_LOG})" >&2
            elif [[ "$SMOKE_EXIT" -ne 0 ]]; then
                # Fix 8: smoke crash (exit!=0 + JSON 空) は SKIP ではなく FAIL 集計
                emit_result "$EXP_ID" 'false' "smoke.sh crash (exit=$SMOKE_EXIT, no valid JSON; log: ${SMOKE_LOG})" "$VS"
                FAIL_COUNT+=1
                echo "FAIL ${EXP_ID} (crash, exit=$SMOKE_EXIT, log: ${SMOKE_LOG})" >&2
            else
                emit_result "$EXP_ID" 'null' "smoke.sh returned invalid JSON (log: ${SMOKE_LOG})" "$VS"
                SKIP_COUNT+=1
                echo "SKIP ${EXP_ID} (invalid smoke JSON)" >&2
            fi
            ;;
        research)
            emit_result "$EXP_ID" 'null' "research-only EXP, no automated check" "$VS"
            SKIP_COUNT+=1
            ;;
        *)
            emit_result "$EXP_ID" 'null' "unknown runner_type: ${RUNNER}" "$VS"
            SKIP_COUNT+=1
            ;;
    esac
done < <(jq -c "$JQ_FILTER" "$MANIFEST")

if [[ "$DRY_RUN" -eq 1 ]]; then
    echo "[dry-run] would target ${RUN_COUNT} experiments" >&2
    rm -rf "$AUDIT_DIR"
    exit 0
fi

# Aggregate index.json
INDEX="${AUDIT_DIR}/index.json"
shopt -s nullglob
jq -s --arg rid "$RUN_ID" --arg gen "$(date -u +%Y-%m-%dT%H:%M:%SZ)" '
    {run_id: $rid, generated_at: $gen, experiments: .,
     summary: {total: length,
               pass: (map(select(.pass == true))  | length),
               fail: (map(select(.pass == false)) | length),
               skip: (map(select(.pass == null))  | length)}}
' "${AUDIT_DIR}"/EXP-*.json > "$INDEX"

{
    echo
    echo "===== EXP run summary ====="
    echo "  audit dir: ${AUDIT_DIR}"
    echo "  run:  ${RUN_COUNT}"
    echo "  pass: ${PASS_COUNT}"
    echo "  fail: ${FAIL_COUNT}"
    echo "  skip: ${SKIP_COUNT}"
} >&2

[[ "$FAIL_COUNT" -gt 0 ]] && exit 1
exit 0
